import type { HookEvent } from '../../types.js';

/**
 * Generate a hook script for a given event type.
 *
 * The generated script is a thin wrapper that imports the vibecheck hook runner
 * from node_modules and calls it with the event type.
 */
export function generateHookScript(event: HookEvent): string {
  return `#!/usr/bin/env node
// Generated by VibeCheck — do not edit manually.
// Regenerate with: npx vibecheck generate

import { executeHook } from '@solanticai/vibecheck/hooks/runner';

executeHook('${event}');
`;
}
